## InvPos — inverse of positive value x^{-1}

#' Inverse position: \eqn{x^{-1}} (for x > 0)
#'
#' @param x An Expression
#' @returns A Power atom with p=-1
#' @export
inv_pos <- function(x) {
  Power(x, -1)
}
